from collections import deque

class Solution:
    def getDirections(self, root, startValue, destValue):
        parent = {}
        stack = [root]
        while stack:
            node = stack.pop()
            if node.left:
                parent[node.left.val] = (node.val, 'L')
                stack.append(node.left)
            if node.right:
                parent[node.right.val] = (node.val, 'R')
                stack.append(node.right)

        adj = {}
        for child_val, (par_val, label) in parent.items():
            adj.setdefault(par_val, []).append((child_val, label))
            adj.setdefault(child_val, []).append((par_val, 'U'))

        visited = {startValue}
        q = deque([(startValue, '')])
        while q:
            val, path = q.popleft()
            if val == destValue:
                return path
            for nxt, label in adj.get(val, []):
                if nxt not in visited:
                    visited.add(nxt)
                    q.append((nxt, path + label))
        return ''

